import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DDNAyvCW.js";const s="/assets/dashboard.Dd8CpGef.png",m=JSON.parse('{"title":"Chaterm Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"docs/index.md","filePath":"docs/index.md"}'),n={name:"docs/index.md"};function i(l,t,d,c,h,p){return o(),a("div",null,t[0]||(t[0]=[r('<h1 id="chaterm-documentation" tabindex="-1">Chaterm Documentation <a class="header-anchor" href="#chaterm-documentation" aria-label="Permalink to &quot;Chaterm Documentation&quot;">​</a></h1><p>Welcome to the Chaterm (/tʃɑːtɜːm/) documentation. Chaterm is an AI-native terminal agent that replaces memorizing shell commands, SQL syntax, and script parameters with natural language. It acts as your DevOps copilot, combining expert SRE knowledge with Agent reasoning to plan, execute, and recover operations end-to-end.</p><p><img src="'+s+'" alt=""></p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><ul><li><strong><a href="/docs/start/downloads/">Download Chaterm</a></strong> -- Install Chaterm on macOS, Windows, or Linux</li><li><strong><a href="/docs/start/quickstart/">Quick Start</a></strong> -- Connect to your first host and run your first AI-assisted command</li><li><strong><a href="/docs/hosts/add-personal">Add a Host</a></strong> -- Register a personal server, bastion host, or router</li><li><strong><a href="/docs/ai/settings/">Configure AI</a></strong> -- Choose your model provider and tune AI behavior</li></ul><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><ul><li><p><strong>Agent Task Planning</strong> -- Decompose multi-step operations automatically. Chaterm analyzes logs, generates commands, adjusts strategy on failure, and completes tasks from build to rollback without manual intervention.</p></li><li><p><strong>Intelligent Command Autocomplete</strong> -- Go beyond history-based suggestions. Get context-aware completions based on your habits, current host environment, and business topology.</p></li><li><p><strong>Chat to AI in Terminal</strong> -- Describe what you want in plain language directly inside the terminal. Chaterm translates intent into executable commands and explains each step.</p></li><li><p><strong>Voice Input Control</strong> -- Issue commands by voice on mobile or desktop. Respond to incidents faster without reaching for a keyboard.</p></li><li><p><strong>MCP Protocol Integration</strong> -- Connect to enterprise knowledge bases like Notion and GitHub through the Model Context Protocol. Extend AI capabilities without custom code.</p></li><li><p><strong>Skills and Extensions</strong> -- Bundle reusable operational workflows as Skills. Share them across teams and trigger them from natural language or shortcuts.</p></li><li><p><strong>Global Consistent Experience</strong> -- Set syntax highlighting and editor preferences once; they follow you to every host. Edit files with a Visual Vim mode that supports mouse operations and intuitive controls.</p></li><li><p><strong>Snippets and Quick Commands</strong> -- Save frequently used commands as reusable snippets. Assign global aliases to complex scripts and execute them in one step.</p></li><li><p><strong>Enterprise-Grade Security</strong> -- Protect data with end-to-end encryption, role-based access control, session-level zero-trust authentication, and comprehensive audit logging.</p></li><li><p><strong>Unified Permission Management</strong> -- Manage digital assets across organizations with enterprise SSO authorization and fine-grained access policies.</p></li></ul><h2 id="popular-pages" tabindex="-1">Popular Pages <a class="header-anchor" href="#popular-pages" aria-label="Permalink to &quot;Popular Pages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Description</th></tr></thead><tbody><tr><td><a href="/docs/terminal/operations/">Terminal Operations</a></td><td>Master split panes, session tabs, and terminal workflows</td></tr><tr><td><a href="/docs/ai/dialogs/">AI Dialog</a></td><td>Learn how to interact with the AI agent effectively</td></tr><tr><td><a href="/docs/ai/llms/">Model List</a></td><td>Browse supported LLM providers and configure your preferred model</td></tr><tr><td><a href="/docs/manage/keys/">Key Management</a></td><td>Manage SSH keys and credentials securely</td></tr><tr><td><a href="/docs/mcp/usage/">MCP Usage Guide</a></td><td>Set up and use MCP servers for extended context</td></tr><tr><td><a href="/docs/skills/usage/">Skills Usage Guide</a></td><td>Create, import, and run operational Skills</td></tr><tr><td><a href="/docs/settings/shortcuts/">Shortcuts</a></td><td>View and customize keyboard shortcuts</td></tr><tr><td><a href="/docs/mobile/quickstart/">Mobile Quick Start</a></td><td>Operate on the go with the Chaterm mobile app</td></tr><tr><td><a href="/docs/contributing/">Contributing Guide</a></td><td>Contribute to Chaterm development</td></tr></tbody></table><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><p>Chaterm offers a free tier and paid plans for teams and enterprises. Review the <a href="/docs/start/pricing/">Pricing page</a> for details on features and limits.</p><h2 id="get-help" tabindex="-1">Get Help <a class="header-anchor" href="#get-help" aria-label="Permalink to &quot;Get Help&quot;">​</a></h2><ul><li>Browse the sidebar to explore all documentation sections.</li><li>Report issues or request features on <a href="https://github.com/chaterm/chaterm" target="_blank" rel="noreferrer">GitHub</a>.</li><li>Contact the team at <a href="mailto:support@chaterm.ai" target="_blank" rel="noreferrer">support@chaterm.ai</a>.</li></ul>',13)]))}const g=e(n,[["render",i]]);export{m as __pageData,g as default};
